// Scoop position in viewBox space (group translation).
const CONE_SCOOP_CX = 266.5;
const CONE_SCOOP_CY = -18;
const CONE_SCOOP_RX = 268;
const CONE_SCOOP_RY = 268;

// Drips relative to scoop center.
const CONE_DRIP_DY_OFFSET = 200;
const CONE_DRIP_RX = 80;
const CONE_DRIP_RY = 80;
const CONE_DRIP_CX_OFFSETS = [-186, -101, 0, 101, 186] as const;

// Drizzle paths relative to scoop center.
const DRIZZLE_PATHS_RELATIVE = [
  "M -162 -39 C -121 -133 -63 -81 -18 -158",
  "M -19 79 C -60 79 -78 70 -100 33",
  "M 158 -117 C 218 -80 227 -18 190 61",
] as const;

export function Cone({ tokens, size, seed, className }: ConeProps) {
  const base = BASE_TOKENS[tokens.base];
  const crumblePositions =
    tokens.crumble === "none"
      ? []
      : makeCrumbleDots({
          seed,
          count: 7,
          centerX: 0,
          centerY: 0,
          radius: CONE_SCOOP_RX,
          edgePadding: 30,
          minDistance: 50,
          maxRetriesPerDot: 8,
          hemisphere: "full",
        });
  const dotRx = 16 * (CONE_SCOOP_RX / 303);
  const dotRy = 10 * (CONE_SCOOP_RX / 303);

  return (
    <div
      className={className}
      style={{
        display: "inline-block",
        width: size,
        height: size * (1319 / 533),
        position: "relative",
      }}
    >
      <svg
        viewBox="0 -400 533 1319"
        width={size}
        height={size * (1319 / 533)}
        preserveAspectRatio="xMidYMid meet"
        fill="none"
        xmlns="http://www.w3.org/2000/svg"
        aria-hidden="true"
      >
        <path d={CONE_BG_PATH} fill="#9A713A" />
        <path d={CONE_WAFFLE_PATH} fill="#E0A756" />
        <path d={CONE_HIGHLIGHT_PATH} fill="#C78F50" />

        <g transform={`translate(${CONE_SCOOP_CX}, ${CONE_SCOOP_CY})`}>
          {CONE_DRIP_CX_OFFSETS.map((dx) => (
            <ellipse
              key={dx}
              cx={dx}
              cy={CONE_DRIP_DY_OFFSET}
              rx={CONE_DRIP_RX}
              ry={CONE_DRIP_RY}
              fill={base.hex}
            />
          ))}

          <ellipse cx={0} cy={0} rx={CONE_SCOOP_RX} ry={CONE_SCOOP_RY} fill={base.hex} />

          {tokens.drizzle !== "none"
            ? DRIZZLE_PATHS_RELATIVE.map((d) => (
                <path
                  key={d}
                  d={d}
                  stroke={DRIZZLE_TOKENS[tokens.drizzle].stroke}
                  strokeOpacity={DRIZZLE_TOKENS[tokens.drizzle].opacity}
                  strokeWidth={20}
                  strokeLinecap="round"
                  fill="none"
                />
              ))
            : null}

          {tokens.crumble !== "none"
            ? crumblePositions.map(({ x, y, rot, index }) => (
                <ellipse
                  key={index}
                  cx={x}
                  cy={y}
                  rx={dotRx}
                  ry={dotRy}
                  fill={getCrumbleFill(tokens.crumble, index)}
                  transform={`rotate(${rot} ${x} ${y})`}
                />
              ))
            : null}
        </g>
      </svg>
    </div>
  );
}

